import { sqrt } from "@stdlib/math";
import { to_fixed } from "@stdlib/decimal";

fn mean(xs: array): f64 {
    let s = 0.0;
    for (x in xs) { s += x; }
    return s / xs.length;
}

fn stddev(xs: array): f64 {
    let m = mean(xs);
    let sq = 0.0;
    for (x in xs) {
        let d = x - m;
        sq += d * d;
    }
    return sqrt(sq / xs.length);
}

let data = [2.0, 4.0, 4.0, 4.0, 5.0, 5.0, 7.0, 9.0];
print(`mean=${to_fixed(mean(data), 2)}`);
print(`stddev=${to_fixed(stddev(data), 2)}`);

